test-code.code:
fun withoutBraces(x: Boolean, y: Boolean) {
    if (x)
        if (y) println("both")
}

fun withBraces(x: Boolean, y: Boolean) {
    if (x) {
        if (y) {
            println("both")
        }
    }
}

fun withElse(x: Boolean, y: Boolean) {
    if (x) {
        if (y) {
            println("both")
        }
    } else {
        println("not x")
    }
}

fun innerWithElse(x: Boolean, y: Boolean) {
    if (x) {
        if (y) {
            println("both")
        } else {
            println("only x")
        }
    }
}

fun twoStatements(x: Boolean, y: Boolean) {
    if (x) {
        doSomething()
        if (y) {
            println("both")
        }
    }
}

fun doSomething() {}

fun merged(x: Boolean, y: Boolean) {
    if (x && y) {
        println("both")
    }
}

fun test(x: Boolean, y: Boolean) {
    if (x) {
        println(if (y) "yes" else "no")
    }
}
